previewCss:
.darma-loader-uiverse-ocean-progress-comet__progress {
  background-color: #ffffff;
  width: 220px;
  height: 20px;
  border-radius: 100px;
  overflow: hidden;
  backface-visibility: hidden;
}
.darma-loader-uiverse-ocean-progress-comet__inner {
  background-image: linear-gradient(to left, var(--loader-color, #00cdac), #00c2c9, #00b4e3, #00a2f1, #008cef, #0088eb, #0085e6, #0081e2, #0090de, #009bd2, #00a3c1, var(--loader-secondary-color, #02aab0));
  height: 100%;
  transform-origin: left;
  animation: darma-loader-uiverse-ocean-progress-comet-oceanProgress 2s infinite;
}
@keyframes darma-loader-uiverse-ocean-progress-comet-oceanProgress {
  0% { transform: scaleX(.1) translateX(-10%); }
  100% { transform: scaleX(.8) translateX(150%); }
}

